mapper.select:
SELECT 
FROM tb_biz_task_execution
WHERE state='RUNNING' AND lease_until IS NOT NULL AND lease_until < #{now}
ORDER BY lease_until ASC,execution_id ASC
LIMIT #{limit}

SELECT 
FROM tb_biz_task_execution
WHERE task_id=#{taskId}
ORDER BY planned_at ASC,id ASC
LIMIT #{limit}

mapper.update:
UPDATE tb_biz_task_execution
SET heartbeat_at=#{heartbeatAt},lease_until=#{leaseUntil},update_time=#{heartbeatAt},version=version+1
WHERE execution_id=#{executionId} AND state='RUNNING' AND claim_token=#{claimToken}

UPDATE tb_biz_task_execution
SET progress_current=#{current},progress_total=#{total},progress_message=#{message},
    progress_revision=#{revision},update_time=#{updateTime},version=version+1
WHERE execution_id=#{executionId} AND state='RUNNING' AND claim_token=#{claimToken}
  AND progress_revision < #{revision} AND progress_current <= #{current}
  AND (progress_total=0 OR progress_total <= #{total})
